// Validate input and start latency timer
const items = $input.all();
const results = [];

for (const item of items) {
  const body = item.json.body || item.json;
  const headers = item.json.headers || {};
  const startTime = Date.now();

  // Validate required fields
  const requiredFields = ['document_type', 'process_line', 'access_roles'];
  const missing = requiredFields.filter(f => !body[f]);
  if (missing.length > 0) {
    throw new Error(`Missing required fields: ${missing.join(', ')}`);
  }

  // Validate document_type
  const validTypes = ['sop', 'fmea', 'rca', 'maintenance'];
  if (!validTypes.includes(body.document_type)) {
    throw new Error(`Invalid document_type: ${body.document_type}. Must be one of: ${validTypes.join(', ')}`);
  }

  // Validate file presence and type
  const fileName = body.file_name || '';
  const ext = fileName.split('.').pop().toLowerCase();
  if (!['pdf', 'docx', 'txt'].includes(ext)) {
    throw new Error(`Unsupported file type: .${ext}. Accepted: pdf, docx, txt`);
  }

  // Generate doc_id
  const makeUuid = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random() * 16 | 0; return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16); }); const docId = makeUuid();

  results.push({
    json: {
      ...body,
      doc_id: docId,
      file_extension: ext,
      file_name: fileName,
      document_type: body.document_type,
      process_line: body.process_line,
      access_roles: Array.isArray(body.access_roles) ? body.access_roles : [body.access_roles],
      revision_number: body.revision_number || 1,
      previous_revision_id: body.previous_revision_id || null,
      ingested_by: body.ingested_by || headers['x-user-id'] || 'system',
      file_content: body.file_content || '',
      _metrics: {
        start_time: startTime,
        ingestion_id: docId
      }
    }
  });
}

return results;

// Extract text content from document based on file type
const items = $('Validate_Input').all();
const results = [];

for (const item of items) {
  const data = item.json;
  let textContent = '';

  switch (data.file_extension) {
    case 'txt':
      // Plain text - use content directly
      textContent = data.file_content || '';
      break;

    case 'pdf':
      // For PDF: content should be base64 encoded or pre-extracted
      // In production, use a dedicated PDF extraction service
      if (data.file_content_base64) {
        // Decode base64 and extract text
        const buffer = Buffer.from(data.file_content_base64, 'base64');
        textContent = buffer.toString('utf-8').replace(/[^\x20-\x7E\n\r\t]/g, ' ');
      } else if (data.file_content) {
        textContent = data.file_content;
      } else {
        throw new Error(`PDF content not provided for ${data.file_name}`);
      }
      break;

    case 'docx':
      // For DOCX: content should be pre-extracted or use extraction service
      if (data.file_content) {
        textContent = data.file_content;
      } else {
        throw new Error(`DOCX content not provided for ${data.file_name}`);
      }
      break;

    default:
      throw new Error(`Unsupported file type: ${data.file_extension}`);
  }

  // Clean text
  textContent = textContent
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/[ \t]+/g, ' ')
    .trim();

  if (textContent.length === 0) {
    throw new Error(`No text content extracted from ${data.file_name}`);
  }

  results.push({
    json: {
      ...data,
      text_content: textContent,
      text_length: textContent.length
    }
  });
}

return results;

// Split text into chunks with overlap for embedding
const items = $input.all();
const results = [];

const CHUNK_SIZE = 1500;
const CHUNK_OVERLAP = 200;
const MIN_CHUNK_SIZE = 100;

for (const item of items) {
  const data = item.json;
  const text = (data.text_content || '').trim();
  if (!text) continue;

  const chunks = [];
  let start = 0;

  while (start < text.length) {
    let end = Math.min(start + CHUNK_SIZE, text.length);

    if (end < text.length) {
      const lastPeriod = text.lastIndexOf('.', end);
      const lastNewline = text.lastIndexOf('\n', end);
      const breakPoint = Math.max(lastPeriod, lastNewline);
      if (breakPoint > start + MIN_CHUNK_SIZE) {
        end = breakPoint + 1;
      }
    }

    const chunkText = text.substring(start, end).trim();
    if (chunkText.length >= MIN_CHUNK_SIZE) {
      chunks.push({
        chunk_index: chunks.length,
        chunk_text: chunkText,
        char_count: chunkText.length,
        token_estimate: Math.ceil(chunkText.length / 4)
      });
    }

    const newStart = end - CHUNK_OVERLAP;
    start = (newStart > start) ? newStart : end;
    if (start >= text.length) break;
  }

  for (const chunk of chunks) {
    results.push({
      json: {
        doc_id: data.doc_id,
        file_name: data.file_name,
        document_type: data.document_type,
        process_line: data.process_line,
        access_roles: data.access_roles,
        revision_number: data.revision_number,
        previous_revision_id: data.previous_revision_id,
        ingested_by: data.ingested_by,
        vector_index: data.document_type,
        total_chunks: chunks.length,
        chunk_index: chunk.chunk_index,
        chunk_text: chunk.chunk_text,
        char_count: chunk.char_count,
        token_estimate: chunk.token_estimate,
        _metrics: data._metrics,
        _retry_count: 0
      }
    });
  }
}

return results;

// Check embedding response and handle retry logic
const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;

  // n8n HTTP node may nest body under .body on some versions
  const data = (raw.body !== undefined && typeof raw.body === 'object') ? raw.body : raw;

  // Check for API-level error in response body
  if (data.error) {
    const apiErr = (typeof data.error === 'object') ? (data.error.message || JSON.stringify(data.error)) : String(data.error);
    throw new Error(`OpenAI API error: ${apiErr}`);
  }

  // Extract embedding - handle standard OpenAI shape: { data: [{ embedding: [...] }] }
  let embedding = null;
  if (data.data && Array.isArray(data.data) && data.data[0] && Array.isArray(data.data[0].embedding)) {
    embedding = data.data[0].embedding;
  } else if (Array.isArray(data) && data[0] && Array.isArray(data[0].embedding)) {
    embedding = data[0].embedding;
  }

  // Get paired chunk data from Split_Into_Chunks
  const prevItem = $('Split_Into_Chunks').item;
  const prevData = (prevItem && prevItem.json) ? prevItem.json : {};
  const retryCount = prevData._retry_count || 0;

  if (!embedding || embedding.length === 0) {
    if (retryCount >= 2) {
      // Max retries exceeded — skip chunk so rest of document can still complete
      console.log(`[Embedding] Skipping chunk ${prevData.chunk_index ?? 'unknown'} after ${retryCount} failed attempts. Response: ${JSON.stringify(data).substring(0, 300)}`);
      continue;
    }
    throw new Error(`Embedding generation failed for chunk ${prevData.chunk_index ?? 'unknown'} - retry ${retryCount + 1}`);
  }

  results.push({
    json: {
      ...prevData,
      vector_uuid: 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => { const r = Math.random() * 16 | 0; return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16); }),
      embedding: embedding,
      embedding_dimensions: embedding.length,
      embedding_model: 'text-embedding-3-large',
      _metrics: {
        ...(prevData._metrics || {}),
        embedding_time: Date.now()
      }
    }
  });
}

return results;

// Aggregate chunk results and prepare document-level metadata insert
const items = $input.all();
const sourceItems = $('Process_Embedding_Response').all();

// Group by doc_id, pulling metadata from the embedding node (which has full chunk data)
const docMap = {};
for (let i = 0; i < items.length; i++) {
  const d = items[i].json;
  const src = (sourceItems[i] || { json: {} }).json;
  const docId = d.doc_id || src.doc_id;
  if (!docId) continue;
  if (!docMap[docId]) {
    docMap[docId] = {
      doc_id: docId,
      file_name: src.file_name,
      document_type: src.document_type,
      process_line: src.process_line,
      access_roles: src.access_roles,
      revision_number: src.revision_number,
      previous_revision_id: src.previous_revision_id,
      ingested_by: src.ingested_by,
      vector_index: src.vector_index,
      chunk_count: 0,
      _metrics: src._metrics
    };
  }
  docMap[docId].chunk_count++;
}

const results = Object.values(docMap).map(doc => ({ json: doc }));
return results;

// Compute all ingestion metrics for Prometheus
const items = $input.all();
const results = [];

for (const item of items) {
  const data = $('Aggregate_Chunks').item.json || {};
  const endTime = Date.now();
  const startTime = (data._metrics && data._metrics.start_time) ? data._metrics.start_time : endTime;
  const latencySeconds = (endTime - startTime) / 1000;
  const retryCount = data._retry_count || 0;
  const superseded = data.previous_revision_id ? 1 : 0;
  const docType = data.document_type || 'unknown';
  const procLine = data.process_line || 'unknown';
  const chunkCount = data.chunk_count || 0;

  const metrics = [
    `# HELP ai_ingestion_total Total document ingestions`,
    `# TYPE ai_ingestion_total counter`,
    `ai_ingestion_total{document_type="${docType}",process_line="${procLine}",status="success"} 1`,
    ``,
    `# HELP ai_ingestion_latency_seconds Ingestion latency in seconds`,
    `# TYPE ai_ingestion_latency_seconds histogram`,
    `ai_ingestion_latency_seconds{document_type="${docType}",process_line="${procLine}",le="1"} ${latencySeconds <= 1 ? 1 : 0}`,
    `ai_ingestion_latency_seconds{document_type="${docType}",process_line="${procLine}",le="5"} ${latencySeconds <= 5 ? 1 : 0}`,
    `ai_ingestion_latency_seconds{document_type="${docType}",process_line="${procLine}",le="10"} ${latencySeconds <= 10 ? 1 : 0}`,
    `ai_ingestion_latency_seconds{document_type="${docType}",process_line="${procLine}",le="30"} ${latencySeconds <= 30 ? 1 : 0}`,
    `ai_ingestion_latency_seconds{document_type="${docType}",process_line="${procLine}",le="60"} ${latencySeconds <= 60 ? 1 : 0}`,
    `ai_ingestion_latency_seconds{document_type="${docType}",process_line="${procLine}",le="+Inf"} 1`,
    `ai_ingestion_latency_seconds_sum{document_type="${docType}",process_line="${procLine}"} ${latencySeconds}`,
    `ai_ingestion_latency_seconds_count{document_type="${docType}",process_line="${procLine}"} 1`,
    ``,
    `# HELP ai_ingestion_chunks_total Total chunks created`,
    `# TYPE ai_ingestion_chunks_total counter`,
    `ai_ingestion_chunks_total{document_type="${docType}",process_line="${procLine}"} ${chunkCount}`,
    ``,
    `# HELP ai_ingestion_retry_total Total embedding retries`,
    `# TYPE ai_ingestion_retry_total counter`,
    `ai_ingestion_retry_total{document_type="${docType}",stage="embedding"} ${retryCount}`,
    ``,
    `# HELP ai_revision_superseded_total Documents marked superseded`,
    `# TYPE ai_revision_superseded_total counter`,
    `ai_revision_superseded_total{document_type="${docType}"} ${superseded}`,
    ``
  ].join('\n');

  results.push({
    json: {
      ...data,
      _prometheus_metrics: metrics,
      _latency_seconds: latencySeconds
    }
  });
}

return results;

// Handle errors with exponential backoff tracking and metric emission
const items = $input.all();
const results = [];

for (const item of items) {
  const error = item.json;
  const errorMessage = error.message || error.error?.message || 'Unknown ingestion error';
  const nodeName = error.node?.name || error.workflow?.lastNodeExecuted || 'unknown';
  const executionId = error.execution?.id || 'unknown';

  // Determine failure stage
  let stage = 'unknown';
  if (nodeName.includes('Embedding')) stage = 'embedding';
  else if (nodeName.includes('Vector')) stage = 'vectordb';
  else if (nodeName.includes('Postgres') || nodeName.includes('Metadata')) stage = 'database';
  else if (nodeName.includes('Extract')) stage = 'extraction';
  else if (nodeName.includes('Validate')) stage = 'validation';

  // Build failure metrics
  const failureMetrics = [
    `# HELP ai_ingestion_failed_total Total failed ingestions`,
    `# TYPE ai_ingestion_failed_total counter`,
    `ai_ingestion_failed_total{stage="${stage}",error_type="${errorMessage.substring(0, 50).replace(/"/g, '')}"} 1`,
    ``,
    `# HELP ai_ingestion_retry_total Total retries during ingestion`,
    `# TYPE ai_ingestion_retry_total counter`,
    `ai_ingestion_retry_total{stage="${stage}"} 1`,
    ``
  ].join('\n');

  results.push({
    json: {
      error_message: errorMessage,
      error_stage: stage,
      error_node: nodeName,
      execution_id: executionId,
      timestamp: new Date().toISOString(),
      _prometheus_metrics: failureMetrics
    }
  });
}

return results;

// Merge results from revision supersede branch and no-revision branch
const items = $input.all();
if (items.length === 0) {
  return $('Aggregate_Chunks').all();
}
return items;
